{
  "name": "FinTrack Pro",
  "description": "A comprehensive personal finance tracker featuring real-time analytics, transaction management, and automated balance calculation with a clean, modern UI."
}

export enum TransactionType {
  INCOME = 'INCOME',
  EXPENSE = 'EXPENSE'
}

export interface Transaction {
  id: string;
  userId: string;
  amount: number;
  type: TransactionType;
  category: string;
  description: string;
  date: string;
  createdAt: string;
}

export interface User {
  id: string;
  email: string;
  name: string;
  token?: string;
}

export interface SummaryData {
  totalBalance: number;
  totalIncome: number;
  totalExpenses: number;
}

export const CATEGORIES = [
  'Housing',
  'Transportation',
  'Food',
  'Utilities',
  'Insurance',
  'Medical',
  'Savings',
  'Personal',
  'Entertainment',
  'Salary',
  'Freelance',
  'Investments',
  'Gift',
  'Other'
];

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

