import { Transaction, User, TransactionType } from '../types';

const STORAGE_KEYS = {
  TRANSACTIONS: 'fintrack_transactions',
  USERS: 'fintrack_users',
  CURRENT_USER: 'fintrack_auth_user'
};

// Helper to delay responses for "realism"
const delay = (ms: number) => new Promise(res => setTimeout(res, ms));

export const api = {
  // AUTH
  async login(email: string, password: string): Promise<User> {
    await delay(600);
    const users: User[] = JSON.parse(localStorage.getItem(STORAGE_KEYS.USERS) || '[]');
    const user = users.find(u => u.email === email);
    if (!user) throw new Error('Invalid email or password');

    const userWithToken = { ...user, token: 'mock-jwt-token-' + Date.now() };
    localStorage.setItem(STORAGE_KEYS.CURRENT_USER, JSON.stringify(userWithToken));
    return userWithToken;
  },

  async register(name: string, email: string, password: string): Promise<User> {
    await delay(800);
    const users: any[] = JSON.parse(localStorage.getItem(STORAGE_KEYS.USERS) || '[]');
    if (users.find(u => u.email === email)) throw new Error('Email already registered');

    const newUser = { id: Date.now().toString(), name, email };
    users.push({ ...newUser, password });
    localStorage.setItem(STORAGE_KEYS.USERS, JSON.stringify(users));

    return this.login(email, password);
  },

  logout() {
    localStorage.removeItem(STORAGE_KEYS.CURRENT_USER);
  },

  getCurrentUser(): User | null {
    const user = localStorage.getItem(STORAGE_KEYS.CURRENT_USER);
    return user ? JSON.parse(user) : null;
  },

  // TRANSACTIONS
  async getTransactions(userId: string): Promise<Transaction[]> {
    await delay(400);
    const transactions: Transaction[] = JSON.parse(localStorage.getItem(STORAGE_KEYS.TRANSACTIONS) || '[]');
    return transactions
      .filter(t => t.userId === userId)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  },

  async addTransaction(data: Omit<Transaction, 'id' | 'createdAt'>): Promise<Transaction> {
    await delay(300);
    const transactions: Transaction[] = JSON.parse(localStorage.getItem(STORAGE_KEYS.TRANSACTIONS) || '[]');
    const newTransaction: Transaction = {
      ...data,
      id: Date.now().toString(),
      createdAt: new Date().toISOString()
    };
    transactions.push(newTransaction);
    localStorage.setItem(STORAGE_KEYS.TRANSACTIONS, JSON.stringify(transactions));
    return newTransaction;
  },

  async updateTransaction(id: string, data: Partial<Transaction>): Promise<Transaction> {
    await delay(300);
    const transactions: Transaction[] = JSON.parse(localStorage.getItem(STORAGE_KEYS.TRANSACTIONS) || '[]');
    const index = transactions.findIndex(t => t.id === id);
    if (index === -1) throw new Error('Transaction not found');

    transactions[index] = { ...transactions[index], ...data };
    localStorage.setItem(STORAGE_KEYS.TRANSACTIONS, JSON.stringify(transactions));
    return transactions[index];
  },

  async deleteTransaction(id: string): Promise<void> {
    await delay(300);
    const transactions: Transaction[] = JSON.parse(localStorage.getItem(STORAGE_KEYS.TRANSACTIONS) || '[]');
    const filtered = transactions.filter(t => t.id !== id);
    localStorage.setItem(STORAGE_KEYS.TRANSACTIONS, JSON.stringify(filtered));
  }
};

import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { Transaction, User, TransactionType, SummaryData } from '../types';
import { api } from '../services/api';

interface FinanceContextType {
  user: User | null;
  transactions: Transaction[];
  summary: SummaryData;
  loading: boolean;
  error: string | null;
  login: (email: string, pass: string) => Promise<void>;
  register: (name: string, email: string, pass: string) => Promise<void>;
  logout: () => void;
  fetchTransactions: () => Promise<void>;
  addTransaction: (t: Omit<Transaction, 'id' | 'userId' | 'createdAt'>) => Promise<void>;
  editTransaction: (id: string, t: Partial<Transaction>) => Promise<void>;
  removeTransaction: (id: string) => Promise<void>;
}

const FinanceContext = createContext<FinanceContextType | undefined>(undefined);

export const FinanceProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(api.getCurrentUser());
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const fetchTransactions = useCallback(async () => {
    if (!user) return;
    setLoading(true);
    try {
      const data = await api.getTransactions(user.id);
      setTransactions(data);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }, [user]);

  useEffect(() => {
    if (user) {
      fetchTransactions();
    }
  }, [user, fetchTransactions]);

  const login = async (email: string, pass: string) => {
    setLoading(true);
    try {
      const u = await api.login(email, pass);
      setUser(u);
      setError(null);
    } catch (err: any) {
      setError(err.message);
      throw err;
    } finally {
      setLoading(false);
    }
  };

  const register = async (name: string, email: string, pass: string) => {
    setLoading(true);
    try {
      const u = await api.register(name, email, pass);
      setUser(u);
      setError(null);
    } catch (err: any) {
      setError(err.message);
      throw err;
    } finally {
      setLoading(false);
    }
  };

  const logout = () => {
    api.logout();
    setUser(null);
    setTransactions([]);
  };

  const addTransaction = async (t: Omit<Transaction, 'id' | 'userId' | 'createdAt'>) => {
    if (!user) return;
    try {
      const newT = await api.addTransaction({ ...t, userId: user.id });
      setTransactions(prev => [newT, ...prev]);
    } catch (err: any) {
      setError(err.message);
    }
  };

  const editTransaction = async (id: string, t: Partial<Transaction>) => {
    try {
      const updated = await api.updateTransaction(id, t);
      setTransactions(prev => prev.map(item => item.id === id ? updated : item));
    } catch (err: any) {
      setError(err.message);
    }
  };

  const removeTransaction = async (id: string) => {
    try {
      await api.deleteTransaction(id);
      setTransactions(prev => prev.filter(item => item.id !== id));
    } catch (err: any) {
      setError(err.message);
    }
  };

  const summary: SummaryData = transactions.reduce((acc, curr) => {
    if (curr.type === TransactionType.INCOME) {
      acc.totalIncome += curr.amount;
      acc.totalBalance += curr.amount;
    } else {
      acc.totalExpenses += curr.amount;
      acc.totalBalance -= curr.amount;
    }
    return acc;
  }, { totalBalance: 0, totalIncome: 0, totalExpenses: 0 });

  return (
    <FinanceContext.Provider value={{
      user, transactions, summary, loading, error,
      login, register, logout, fetchTransactions,
      addTransaction, editTransaction, removeTransaction
    }}>
      {children}
    </FinanceContext.Provider>
  );
};

export const useFinance = () => {
  const context = useContext(FinanceContext);
  if (!context) throw new Error('useFinance must be used within a FinanceProvider');
  return context;
};

