export const DATE_PRESETS = {
  THIS_MONTH: 'This Month',
  LAST_MONTH: 'Last Month',
  THIS_YEAR: 'This Year',
  LAST_30_DAYS: 'Last 30 Days',
  CUSTOM: 'Custom Range'
};

import React, { createContext, useContext, useState, useEffect, useCallback, useMemo } from 'react';
import { Transaction, User, TransactionType, SummaryData, DateRange, DATE_PRESETS } from '../types';
import { api } from '../services/api';

interface FinanceContextType {
  user: User | null;
  transactions: Transaction[];
  filteredTransactions: Transaction[];
  summary: SummaryData;
  loading: boolean;
  error: string | null;
  dateRange: DateRange;
  setDateRange: (range: DateRange) => void;
  login: (email: string, pass: string) => Promise<void>;
  register: (name: string, email: string, pass: string) => Promise<void>;
  logout: () => void;
  fetchTransactions: () => Promise<void>;
  addTransaction: (t: Omit<Transaction, 'id' | 'userId' | 'createdAt'>) => Promise<void>;
  editTransaction: (id: string, t: Partial<Transaction>) => Promise<void>;
  removeTransaction: (id: string) => Promise<void>;
}

const getDefaultDateRange = (): DateRange => {
  const now = new Date();
  const firstDay = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().split('T')[0];
  const lastDay = new Date(now.getFullYear(), now.getMonth() + 1, 0).toISOString().split('T')[0];
  return {
    startDate: firstDay,
    endDate: lastDay,
    label: DATE_PRESETS.THIS_MONTH
  };
};

const FinanceContext = createContext<FinanceContextType | undefined>(undefined);

export const FinanceProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(api.getCurrentUser());
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [dateRange, setDateRange] = useState<DateRange>(getDefaultDateRange());
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const fetchTransactions = useCallback(async () => {
    if (!user) return;
    setLoading(true);
    try {
      const data = await api.getTransactions(user.id);
      setTransactions(data);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }, [user]);

  useEffect(() => {
    if (user) {
      fetchTransactions();
    }
  }, [user, fetchTransactions]);

  const login = async (email: string, pass: string) => {
    setLoading(true);
    try {
      const u = await api.login(email, pass);
      setUser(u);
      setError(null);
    } catch (err: any) {
      setError(err.message);
      throw err;
    } finally {
      setLoading(false);
    }
  };

  const register = async (name: string, email: string, pass: string) => {
    setLoading(true);
    try {
      const u = await api.register(name, email, pass);
      setUser(u);
      setError(null);
    } catch (err: any) {
      setError(err.message);
      throw err;
    } finally {
      setLoading(false);
    }
  };

  const logout = () => {
    api.logout();
    setUser(null);
    setTransactions([]);
  };

  const addTransaction = async (t: Omit<Transaction, 'id' | 'userId' | 'createdAt'>) => {
    if (!user) return;
    try {
      const newT = await api.addTransaction({ ...t, userId: user.id });
      setTransactions(prev => [newT, ...prev]);
    } catch (err: any) {
      setError(err.message);
    }
  };

  const editTransaction = async (id: string, t: Partial<Transaction>) => {
    try {
      const updated = await api.updateTransaction(id, t);
      setTransactions(prev => prev.map(item => item.id === id ? updated : item));
    } catch (err: any) {
      setError(err.message);
    }
  };

  const removeTransaction = async (id: string) => {
    try {
      await api.deleteTransaction(id);
      setTransactions(prev => prev.filter(item => item.id !== id));
    } catch (err: any) {
      setError(err.message);
    }
  };

  const filteredTransactions = useMemo(() => {
    const start = new Date(dateRange.startDate);
    const end = new Date(dateRange.endDate);
    end.setHours(23, 59, 59, 999);

    return transactions.filter(t => {
      const tDate = new Date(t.date);
      return tDate >= start && tDate <= end;
    });
  }, [transactions, dateRange]);

  const summary: SummaryData = useMemo(() => {
    return filteredTransactions.reduce((acc, curr) => {
      if (curr.type === TransactionType.INCOME) {
        acc.totalIncome += curr.amount;
        acc.totalBalance += curr.amount;
      } else {
        acc.totalExpenses += curr.amount;
        acc.totalBalance -= curr.amount;
      }
      return acc;
    }, { totalBalance: 0, totalIncome: 0, totalExpenses: 0 });
  }, [filteredTransactions]);

  return (
    <FinanceContext.Provider value={{
      user, transactions, filteredTransactions, summary, loading, error, dateRange, setDateRange,
      login, register, logout, fetchTransactions,
      addTransaction, editTransaction, removeTransaction
    }}>
      {children}
    </FinanceContext.Provider>
  );
};

export const useFinance = () => {
  const context = useContext(FinanceContext);
  if (!context) throw new Error('useFinance must be used within a FinanceProvider');
  return context;
};

import React, { useState } from 'react';
import { useFinance } from '../context/FinanceContext';
import { DATE_PRESETS, DateRange } from '../types';

const DateRangePicker: React.FC = () => {
  const { dateRange, setDateRange } = useFinance();
  const [isOpen, setIsOpen] = useState(false);

  const applyPreset = (preset: string) => {
    const now = new Date();
    let start = new Date();
    let end = new Date();
    let label = preset;

    switch (preset) {
      case DATE_PRESETS.THIS_MONTH:
        start = new Date(now.getFullYear(), now.getMonth(), 1);
        end = new Date(now.getFullYear(), now.getMonth() + 1, 0);
        break;
      case DATE_PRESETS.LAST_MONTH:
        start = new Date(now.getFullYear(), now.getMonth() - 1, 1);
        end = new Date(now.getFullYear(), now.getMonth(), 0);
        break;
      case DATE_PRESETS.THIS_YEAR:
        start = new Date(now.getFullYear(), 0, 1);
        end = new Date(now.getFullYear(), 11, 31);
        break;
      case DATE_PRESETS.LAST_30_DAYS:
        start = new Date();
        start.setDate(now.getDate() - 30);
        end = new Date();
        break;
      default:
        return;
    }

    setDateRange({
      startDate: start.toISOString().split('T')[0],
      endDate: end.toISOString().split('T')[0],
      label
    });
    setIsOpen(false);
  };

  const handleCustomDateChange = (type: 'start' | 'end', value: string) => {
    const newRange = { ...dateRange, label: DATE_PRESETS.CUSTOM };
    if (type === 'start') newRange.startDate = value;
    else newRange.endDate = value;
    setDateRange(newRange);
  };

  return (
    <div className="relative">
      <button
        onClick={() => setIsOpen(!isOpen)}
        className="flex items-center space-x-2 bg-white px-4 py-2 rounded-xl border border-gray-200 text-sm font-semibold text-gray-700 hover:bg-gray-50 transition-colors shadow-sm"
      >
        <i className="far fa-calendar-alt text-blue-600"></i>
        <span>{dateRange.label}:</span>
        <span className="text-gray-500 font-normal">
          {new Date(dateRange.startDate).toLocaleDateString()} - {new Date(dateRange.endDate).toLocaleDateString()}
        </span>
        <i className={`fas fa-chevron-down text-xs transition-transform ${isOpen ? 'rotate-180' : ''}`}></i>
      </button>

      {isOpen && (
        <>
          <div className="fixed inset-0 z-10" onClick={() => setIsOpen(false)}></div>
          <div className="absolute right-0 mt-2 w-72 bg-white rounded-2xl shadow-xl border border-gray-100 z-20 p-4">
            <p className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-3">Presets</p>
            <div className="space-y-1 mb-4">
              {[DATE_PRESETS.THIS_MONTH, DATE_PRESETS.LAST_MONTH, DATE_PRESETS.LAST_30_DAYS, DATE_PRESETS.THIS_YEAR].map(preset => (
                <button
                  key={preset}
                  onClick={() => applyPreset(preset)}
                  className={`w-full text-left px-3 py-2 rounded-lg text-sm transition-colors ${
                    dateRange.label === preset ? 'bg-blue-50 text-blue-600 font-bold' : 'text-gray-600 hover:bg-gray-50'
                  }`}
                >
                  {preset}
                </button>
              ))}
            </div>

            <p className="text-xs font-bold text-gray-400 uppercase tracking-widest mb-3">Custom Range</p>
            <div className="space-y-3">
              <div>
                <label className="text-[10px] text-gray-400 uppercase font-bold">Start Date</label>
                <input
                  type="date"
                  className="w-full mt-1 px-3 py-2 border border-gray-100 rounded-lg text-sm focus:ring-2 focus:ring-blue-100 outline-none"
                  value={dateRange.startDate}
                  onChange={(e) => handleCustomDateChange('start', e.target.value)}
                />
              </div>
              <div>
                <label className="text-[10px] text-gray-400 uppercase font-bold">End Date</label>
                <input
                  type="date"
                  className="w-full mt-1 px-3 py-2 border border-gray-100 rounded-lg text-sm focus:ring-2 focus:ring-blue-100 outline-none"
                  value={dateRange.endDate}
                  onChange={(e) => handleCustomDateChange('end', e.target.value)}
                />
              </div>
            </div>
          </div>
        </>
      )}
    </div>
  );
};

